import { isNumber, isString } from 'lodash-es';

import { _sanitizeSymbol as sanitizeSymbol } from '../../../../../../../core/utils/sanitize-symbol.js';
import { MultiDataPointShape } from '../../../../shape/MultiDataPointShape.js';
import { SingleDataPointShape } from '../../../../shape/SingleDataPointShape.js';
import { AnnotationsMarkerConfig } from '../../../types/annotations-marker-props.js';
import { isRangeMarker } from '../../../utils/is-range-marker.js';

export function getSymbol(marker: AnnotationsMarkerConfig) {
  const { color, symbol } = marker;

  if (symbol) {
    if (isNumber(symbol) || isString(symbol)) {
      return sanitizeSymbol(`${symbol}`);
    }

    return symbol;
  }

  return isRangeMarker(marker) ? (
    <MultiDataPointShape color={color} />
  ) : (
    <SingleDataPointShape color={color} />
  );
}
